import React from "react"
import { StaticQuery, graphql } from "gatsby"
import CenterHeader from "../CenterHeader"

const CareersTable = props => (
  <div>
    <CenterHeader>{props.title}</CenterHeader>
    <div style={{ overflowX: "auto" }}>
      <table style={{ fontSize: 16 }}>
        <col width="160" />
        <tr>
          <th>Name</th>
          <th>Position</th>
          <th>Company</th>
          <th>Location</th>
        </tr>
        {props.children}
      </table>
    </div>
  </div>
)

class CareersTables extends React.Component {
  render() {
    return (
      <StaticQuery
        query={graphql`
          {
            fullTimeOffers2020: allCareersXlsxFullTimeOffers2020 {
              nodes {
                Name
                Position
                Company
                Location
              }
            }

            internships2019: allCareersXlsxInternships2019 {
              nodes {
                Name
                Position
                Company
                Location
              }
            }

            fullTimeOffers2019: allCareersXlsxFullTimeOffers2019 {
              nodes {
                Name
                Position
                Company
                Location
              }
            }
          }
        `}
        render={data => (
          <div>
            <CareersTable title={`2020 Full Time Offers`}>
              {data.fullTimeOffers2020.nodes.map(node => (
                <tr>
                  <td>{node.Name}</td>
                  <td>{node.Position}</td>
                  <td>{node.Company}</td>
                  <td>{node.Location}</td>
                </tr>
              ))}
            </CareersTable>
            <CareersTable title={`2019 Internships`}>
              {data.internships2019.nodes.map(node => (
                <tr>
                  <td>{node.Name}</td>
                  <td>{node.Position}</td>
                  <td>{node.Company}</td>
                  <td>{node.Location}</td>
                </tr>
              ))}
            </CareersTable>
            <CareersTable title={`2019 Full Time Offers`}>
              {data.fullTimeOffers2019.nodes.map(node => (
                <tr>
                  <td>{node.Name}</td>
                  <td>{node.Position}</td>
                  <td>{node.Company}</td>
                  <td>{node.Location}</td>
                </tr>
              ))}
            </CareersTable>
          </div>
        )}
      />
    )
  }
}

export default CareersTables
